import { forwardRef } from "react";
import type { HTMLAttributes, ReactNode } from "react";
import { Slot } from "@radix-ui/react-slot";
import * as styles from "./Legend.css";
import { clsx } from "clsx";

export interface LegendCustomProps {
  /**
   * The legend text
   */
  children: ReactNode;

  /**
   * Whether the field is required (shows asterisk)
   * @default false
   */
  required?: boolean;

  /**
   * When true, the component will render its child element instead of the default
   * `<legend>` element, merging the Legend's props and behavior onto the child.
   *
   * This is useful when integrating with component libraries like react-aria that
   * require their own label components for accessibility (e.g., CheckboxGroup, RadioGroup).
   *
   * @example
   * // Using with react-aria-components CheckboxGroup
   * <Legend asChild>
   *   <AriaLabel>Favorite sports</AriaLabel>
   * </Legend>
   *
   * @default false
   */
  asChild?: boolean;
}

export interface LegendProps
  extends
    Omit<HTMLAttributes<HTMLLegendElement>, keyof LegendCustomProps>,
    LegendCustomProps {}

export const Legend = forwardRef<HTMLLegendElement, LegendProps>(
  (
    { children, required = false, asChild = false, className, ...props },
    ref
  ) => {
    const legendClassName = clsx(styles.legend({ required }), className);

    const Component = asChild ? Slot : "legend";

    return (
      <Component
        ref={ref}
        className={legendClassName}
        {...(required && { "data-required": true })}
        {...props}
      >
        {children}
      </Component>
    );
  }
);

Legend.displayName = "Legend";
